static POOL_MANAGER: OnceCell<PoolManagerInner> = OnceCell::new();

/// Global singleton pool manager for synchronous access to the transaction pool
/// during block verification to prevent race conditions with async system transactions.
#[derive(Debug)]
pub struct PoolManager;

pub fn initialize<P, T>(pool: Arc<P>) -> Result<(), &'static str>
where
    P: TransactionPool<Transaction = T> + Send + Sync + 'static,
    T: EthPoolTransaction + 'static,
{
    let pool_clone = pool.clone();
    let manager = PoolManagerInner {
        remove_transactions: Box::new(move |hashes| {
            let _ = pool_clone.remove_transactions(hashes);
        }),
    };

    POOL_MANAGER.set(manager).map_err(|_| "PoolManager already initialized")?;
    debug!("PoolManager singleton initialized successfully");
    Ok(())
}

